import { supabase } from './supabase'
import type { Category, Difficulty, MasteryStatus, WordClass } from '@/store/useFilterStore'

// Gemeinsamer Vocab-Loader für alle Modi außer Sätze.
//
// Nimmt den globalen Filter-State, baut die WHERE-Clause + ggf. clientseitige
// Mastery-Filterung (LEFT JOIN ist in PostgREST nur via embedded resources,
// das wäre Schema-Noise; im MVP machen wir Mastery clientside).

export type VocabCard = {
  id: number
  hungarian: string
  phonetic: string | null
  german: string
  latin_term: string | null
  example_hu: string | null
  example_de: string | null
  category: string
  word_class: string | null
  difficulty_base: number | null
}

type FilterInput = {
  category: Category
  wordClass: WordClass
  difficulty: Difficulty
  mastery: MasteryStatus
}

export function shuffle<T>(arr: T[]): T[] {
  const copy = [...arr]
  for (let i = copy.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1))
    ;[copy[i], copy[j]] = [copy[j], copy[i]]
  }
  return copy
}

export function pickRandom<T>(arr: T[], n: number): T[] {
  return shuffle(arr).slice(0, Math.min(n, arr.length))
}

/**
 * Lädt vocab_medical mit Filter + (optional) clientseitiger Mastery-Filterung
 * gegen srs_medical. Gibt Cards zurück, die in der WHERE-Clause matchen.
 */
export async function loadFilteredVocab(
  filter: FilterInput,
  userId: string | null
): Promise<VocabCard[]> {
  let q = supabase
    .from('vocab_medical')
    .select(
      'id, hungarian, phonetic, german, latin_term, example_hu, example_de, category, word_class, difficulty_base'
    )

  if (filter.category !== 'all') q = q.eq('category', filter.category)
  if (filter.wordClass !== 'all') {
    const dbVal = filter.wordClass === 'adjective' ? 'adj' : filter.wordClass
    q = q.eq('word_class', dbVal)
  }
  if (filter.difficulty === 'easy') q = q.lte('difficulty_base', 2)
  if (filter.difficulty === 'medium') q = q.eq('difficulty_base', 3)
  if (filter.difficulty === 'hard') q = q.gte('difficulty_base', 4)

  const { data: cards, error } = await q
  if (error) throw error
  let result = (cards ?? []) as VocabCard[]

  // Mastery-Filter clientseitig
  if (userId && filter.mastery !== 'all') {
    const { data: srs } = await supabase
      .from('srs_medical')
      .select('card_id, repetitions, production_mastered_at')
      .eq('user_id', userId)
    type SrsLite = { card_id: number; repetitions: number; production_mastered_at: string | null }
    const m = new Map<number, SrsLite>()
    for (const r of (srs ?? []) as SrsLite[]) m.set(r.card_id, r)

    result = result.filter((card) => {
      const s = m.get(card.id)
      switch (filter.mastery) {
        case 'unmastered': return !s || s.production_mastered_at === null
        case 'mastered': return !!s && s.repetitions >= 3
        case 'production_mastered': return !!s && s.production_mastered_at !== null
        default: return true
      }
    })
  }

  return result
}
